VALUES
  ('disabled-64311456-moex-00285', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政規則之敘述，下列何者錯誤？', '["行政機關訂定之公務員加班時數之限制，屬行政規則，須登載於政府 公報", "行政規則須下達下級機關或屬官", "行政規則對行政法院無拘束力", "行政規則之廢止得由發布機關為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00286', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於法規命令之敘述，下列何者錯誤？', '["其內容應明列法律授權之依據", "行政法院應受法規命令之拘束，無審查權限", "除由行政機關自行草擬者外，其訂定並得由人民或團體提議為之", "其發布應刊登政府公報或新聞紙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00287', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '行政機關作成行政處分時，關於附款之附加，下列敘述何者正確？', '["在環境影響評估下，系爭開發案對環境有重大影響而依法應駁回時，亦 得以附條件之方式通過環評審查", "行政機關對於處分之作成無裁量權，但為確保行政處分法定要件之履 行，而以該要件為附款內容", "在環境影響評估下，以要求開發單位應興建商場促進在地經濟發展為條 件，通過環評審查", "行政機關作成授益處分而附加負擔，於授益處分內容實現時，該負擔始 生效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00288', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '下列何者非屬行政處分？', '["交通警察以手勢指揮車輛", "以電腦等自動化裝置核定之稅額通知書", "限制車輛與行人通行之交通號誌", "解聘或停聘公立學校教師"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00289', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '行政機關作成限制人民權利之行政處分前，應給予當事人陳述意見機會， 下列敘述何者正確？', '["當事人不得以言詞代替陳述書", "陳述意見應由本人為之，不得委任代理人", "限制義務人出境避免其潛逃，仍應給予義務人陳述意見機會", "製作大量同種類限制權利之行政處分，無須給予陳述意見機會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00290', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於具有瑕疵行政處分之效力，下列敘述何者錯誤？', '["若具有重大明顯之瑕疵，該處分無效", "有瑕疵之行政處分若可補正，經補正後即治癒其瑕疵", "行政處分有誤寫、誤繕之顯然錯誤者，不影響處分之效力", "教示錯誤之瑕疵，屬於得撤銷之行政處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00291', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '行政機關選擇與人民以合意之方式，相互負擔各自不同之權利義務，以完 成行政任務。該合意行為，稱為：', '["行政命令", "行政處分", "意思通知", "行政契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00292', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '下列何者非屬公法上契約關係？', '["衛生福利部中央健康保險署與各醫事服務機構所締結全民健康保險特約", "土地徵收需用土地人與土地所有權人依規定進行協議價購之約定", "經濟部依其所訂定之作業要點與離岸風電開發業者簽訂之契約", "台灣電力公司跟再生能源發電公司締結之購電契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00293', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '行政機關對人民作成附負擔之許可處分，若人民未履行負擔，行政機關擬 使該許可失效，應為下列何種行為？', '["授益處分之撤銷", "非授益處分之撤銷", "授益處分之廢止", "非授益處分之廢止"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00294', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政罰之成立要件，下列敘述何者正確？', '["甲明知劃有紅線處，不得暫停，仍將車輛停於紅線處，應推論具有故意", "A遛狗時，不清理狗排洩物，乙視若無睹，乙已構成行政罰上之違反秩 序行為", "丙依習俗於街道上搭設帳棚進行喪禮法事，構成阻卻違法事由", "丁於自己之土地傾倒廢土，後將土地所有權移轉給戊，戊不承受丁之狀 態責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL)
